/*
 * Dark anthracite panel that renders a live preview of the command the user
 * will paste into their terminal. Used inside NewIssueModal for all three
 * modes (task / pipeline / iterate). Display-only: does NOT call the API.
 * The real command string (with the server-escaped values + actions-substitute
 * output) is generated by the server at Launch time; this preview mirrors
 * the shape so the user knows what is coming.
 *
 * Mode drives the 4px left-stripe color:
 *   task      -> var(--color-warning)
 *   pipeline  -> var(--color-purple)
 *   iterate   -> var(--color-success)
 *
 * Phase B2 - iterate 3 remediation. Visual parity with
 * webui/designs/screens/{new-task,new-pipeline,new-iterate}-dialog.html.
 *
 * Iterate 3.7c-3 - the in-panel Copy button was removed. The footer's
 * Launch button already copies the command to the clipboard (plus moves
 * the task to In Progress), so a second Copy control inside the preview
 * was redundant and doubled the affordance. The onCopy helper + Copy/
 * Check icon imports are intentionally gone.
 */

import { useEffect, useMemo, useState } from "react";
import { Eye, EyeOff } from "lucide-react";

export type CommandPreviewMode = "new-task" | "new-pipeline" | "new-iterate" | "new-plain";

/**
 * Pre-resolved CLI parameter for preview rendering. Mirrors the server's
 * ResolvedParam — kept independent here so the preview path doesn't need
 * to import server types or duplicate the validation logic.
 *
 * iterate/preview-params-render: render selected params live in the
 * preview so what-you-see equals what-you-paste.
 */
export interface PreviewParam {
  cli_flag: string;
  value?: string;
  separator: "space" | "equals" | "none";
  sensitive?: boolean;
}

/**
 * Fixed-length mask for sensitive values in the preview. 8 chars,
 * length-independent — preserving original token length would leak
 * entropy to anyone shoulder-surfing or screen-recording the modal.
 */
const SECRET_MASK = "********";

export interface CommandPreviewPanelProps {
  mode: CommandPreviewMode;
  title: string;
  description: string;
  projectPath: string;
  sessionUuid: string;
  /** "guided" | "autonomous" - only emitted (as --autonomous) when autonomous.
   *  Pass undefined for task mode which has no autonomy flag. */
  autonomy?: "guided" | "autonomous";
  /** Phase id (e.g. "build") - task-mode only; drives slash command. */
  phaseId?: string;
  /** Phase label (e.g. "Build") - task-mode only; drives --name prefix. */
  phaseLabel?: string;
  /** Plugin dirs to include as space-separated --plugin-dir flags. Optional. */
  pluginDirs?: string[];
  /**
   * Live CLI parameters from the modal's Advanced section. Rendered in
   * declared order; sensitive values masked with a fixed-length placeholder
   * unless the in-panel reveal toggle is on.
   */
  parameters?: PreviewParam[];
  /** Debounce the text update so rapid typing doesn't re-layout every keystroke.
   *  Matches classifyPhase's 250ms cadence. */
  debounceMs?: number;
}

/** Render a single param in the same shape used by `formatParameter` on the server. */
function renderParamToken(p: PreviewParam, mask: boolean): string {
  const value = p.value;
  if (value === undefined) return ` ${p.cli_flag}`;
  const display = mask && p.sensitive ? SECRET_MASK : value;
  if (p.separator === "equals") return ` ${p.cli_flag}=${display}`;
  if (p.separator === "none") return ` ${p.cli_flag}${display}`;
  return ` ${p.cli_flag} ${display}`;
}

function slashFor(mode: CommandPreviewMode, phaseId?: string): string {
  if (mode === "new-pipeline") return "/shipwright-run";
  if (mode === "new-iterate") return "/shipwright-iterate";
  return phaseId ? `/shipwright-${phaseId}` : "/shipwright-build";
}

function namePrefix(mode: CommandPreviewMode, phaseLabel?: string): string {
  if (mode === "new-pipeline") return "Pipeline";
  if (mode === "new-iterate") return "Iterate";
  return phaseLabel ?? "Task";
}

function buildCommandText(opts: {
  mode: CommandPreviewMode;
  title: string;
  description: string;
  projectPath: string;
  sessionUuid: string;
  autonomy?: "guided" | "autonomous";
  phaseId?: string;
  phaseLabel?: string;
  pluginDirs?: string[];
  parameters?: PreviewParam[];
  /** When false, sensitive params are rendered with the SECRET_MASK. */
  revealSecrets?: boolean;
}): string {
  const t = opts.title.trim() || "Untitled";
  const namePre = namePrefix(opts.mode, opts.phaseLabel);
  // Escape `\` before `"` so a backslash can't slip the closing quote in this
  // preview string (CodeQL js/incomplete-sanitization). Display-only — the
  // server does the real per-shell quoting (qPs/qCmd/qPosix).
  const quotedName = `"${namePre}: ${t.replace(/\\/g, "\\\\").replace(/"/g, '\\"')}"`;
  const projectPath = opts.projectPath || "<project-path>";
  const sessionUuid = opts.sessionUuid || "<session-uuid>";
  const pluginDirsFlag =
    opts.pluginDirs && opts.pluginDirs.length > 0
      ? ` \\n    --plugin-dir ${opts.pluginDirs.join(" --plugin-dir ")}`
      : "";
  const desc = opts.description.trim();

  // 2026-04-23 — iterate-20260423-launch-cwd-prefix. The pasted command
  // sets cwd via a `cd … && claude …` prefix so the skill runs with the
  // project as working directory regardless of where the terminal was
  // parked. POSIX flavor shown here for legibility; the real server
  // output is shell-aware (Set-Location for PS, `cd /d` for cmd).
  const cdPrefix = `cd "${projectPath}" && `;

  // iterate/fix-adopt-prompt-shape — slash + autonomy + params +
  // description go INTO ONE quoted initial-prompt arg (matches the
  // server's {task.initial_prompt} substitution). --add-dir is gone
  // (cd prefix already sets cwd). Skill flags belong INSIDE this
  // quoted prompt — Claude treats it as the user's first message in
  // interactive mode.
  const innerSlash = slashFor(opts.mode, opts.phaseId);
  const innerAutonomy = opts.autonomy === "autonomous" ? " --autonomous" : "";
  const innerParams =
    opts.parameters && opts.parameters.length > 0
      ? opts.parameters
          .map((p) => renderParamToken(p, !opts.revealSecrets))
          .join("")
      : "";
  const innerDesc = desc ? ` ${desc}` : "";
  const initialPrompt = `${innerSlash}${innerAutonomy}${innerParams}${innerDesc}`;
  // Escape embedded `"` in the preview's outer double-quote — the
  // SERVER uses per-shell quoting (single-quotes for POSIX/PS where
  // embedded `"` is fine), but the preview always shows double-quotes
  // as a teaching aid. Without this escape, a description like
  // `say "hi"` would render as a broken preview line (review fix).
  // `\` is escaped first so it can't slip the closing quote (CodeQL
  // js/incomplete-sanitization).
  const escapedPrompt = initialPrompt
    .replace(/\\/g, "\\\\")
    .replace(/"/g, '\\"');

  return (
    `$ ${cdPrefix}claude \\n` +
    `    --session-id ${sessionUuid} \\n` +
    `    --name ${quotedName}` +
    pluginDirsFlag +
    ` \\n    "${escapedPrompt}"`
  );
}

function stripeColorFor(mode: CommandPreviewMode): string {
  if (mode === "new-pipeline") return "var(--color-purple)";
  if (mode === "new-iterate") return "var(--color-success)";
  return "var(--color-warning)";
}

export function CommandPreviewPanel({
  mode,
  title,
  description,
  projectPath,
  sessionUuid,
  autonomy,
  phaseId,
  phaseLabel,
  pluginDirs,
  parameters,
  debounceMs = 250,
}: CommandPreviewPanelProps) {
  const [debouncedInputs, setDebouncedInputs] = useState({
    title,
    description,
    autonomy,
    phaseId,
    phaseLabel,
    parameters,
  });
  useEffect(() => {
    const handle = setTimeout(() => {
      setDebouncedInputs({ title, description, autonomy, phaseId, phaseLabel, parameters });
    }, debounceMs);
    return () => clearTimeout(handle);
  }, [title, description, autonomy, phaseId, phaseLabel, parameters, debounceMs]);

  // In-panel reveal state for sensitive params. Local + transient — collapses
  // back to false on every full-component remount (modal close → reopen
  // unmounts the panel, so this is automatic).
  const [revealSecrets, setRevealSecrets] = useState(false);
  const hasSensitive = useMemo(
    () => (debouncedInputs.parameters ?? []).some((p) => p.sensitive),
    [debouncedInputs.parameters],
  );

  const commandText = useMemo(
    () =>
      buildCommandText({
        mode,
        title: debouncedInputs.title,
        description: debouncedInputs.description,
        projectPath,
        sessionUuid,
        autonomy: debouncedInputs.autonomy,
        phaseId: debouncedInputs.phaseId,
        phaseLabel: debouncedInputs.phaseLabel,
        pluginDirs,
        parameters: debouncedInputs.parameters,
        revealSecrets,
      }),
    [mode, debouncedInputs, projectPath, sessionUuid, pluginDirs, revealSecrets],
  );

  return (
    <div
      data-testid="command-preview-panel"
      className="relative overflow-x-auto rounded-[var(--radius-button,8px)] px-[18px] py-[14px] font-mono text-[12px] leading-[1.7]"
      style={{
        background: "var(--dark)",
        color: "var(--inset)",
        borderLeft: `4px solid ${stripeColorFor(mode)}`,
      }}
    >
      {hasSensitive && (
        <button
          type="button"
          data-testid="command-preview-reveal"
          onClick={() => setRevealSecrets((s) => !s)}
          aria-label={revealSecrets ? "Hide secrets" : "Show secrets"}
          className="absolute right-2 top-2 inline-flex items-center gap-1 rounded-[4px] bg-dark-2 px-2 py-1 text-[10px] font-medium text-faint hover:bg-[var(--dark-line)] hover:text-inset"
        >
          {revealSecrets ? <EyeOff size={11} /> : <Eye size={11} />}
          {revealSecrets ? "Hide" : "Show"} secrets
        </button>
      )}
      <pre
        className="font-mono text-[12px] leading-[1.7] text-inset"
        style={{ whiteSpace: "nowrap" }}
      >
        {commandText}
      </pre>
    </div>
  );
}
